    46→  const [isRouting, setIsRouting] = useState(false);
    47→  const [searchEnabled, setSearchEnabled] = useState(() => readSearchToggle(mode));
    48→  const [showSlashMenu, setShowSlashMenu] = useState(false);
    49→  const [slashQuery, setSlashQuery] = useState('');
    50→  const [activePrefix, setActivePrefix] = useState(null);
    51→  const [dockMode, setDockMode] = useState(null); // null = 자동, 'chat', 'canvas'
    52→  const location = useLocation();
    53→  const navigate = useNavigate();
    54→  const { messages, agentStatus, isStreamingActive } = useTutor();
    55→  const { openTutor } = useTutorUI();
    56→  const { keyboardOffset, shouldHideBottomNav } = useKeyboardInset();
    57→  const hasActiveSession = Array.isArray(messages) && messages.length > 0;
    58→  const isAgentRoute = location.pathname.startsWith('/agent');
    59→  const hideBottomNav = shouldHideBottomNav;
    60→
    61→  useEffect(() => {
    62→    try {
    63→      localStorage.setItem(SEARCH_TOGGLE_KEY, searchEnabled ? '1' : '0');
    64→    } catch {
    65→      // ignore storage errors
    66→    }
    67→  }, [searchEnabled]);
    68→
    69→  useEffect(() => {
    70→    try {
    71→      const hasStoredValue = localStorage.getItem(SEARCH_TOGGLE_KEY);
    72→      if (hasStoredValue === null) {
    73→        setSearchEnabled(mode === 'stock');
    74→      }
    75→    } catch {
    76→      setSearchEnabled(mode === 'stock');
    77→    }
    78→  }, [mode]);
    79→
    80→  useEffect(() => {
    81→    document.documentElement.style.setProperty('--keyboard-offset', `${keyboardOffset}px`);
    82→    return () => {
    83→      document.documentElement.style.setProperty('--keyboard-offset', '0px');
    84→    };
    85→  }, [keyboardOffset]);
    86→
    87→  const baseContextPayload = useMemo(() => {
    88→    if (mode === 'stock' && location.state?.stockContext) {
    89→      return location.state.stockContext;
    90→    }
    91→
    92→    if (mode === 'home') {
    93→      return readSessionJson('adelie_home_context');
    94→    }
    95→
    96→    if (mode === 'education') {
    97→      return readSessionJson('adelie_education_context');
    98→    }
    99→
   100→    return null;
   101→  }, [location.state, mode]);
   102→
   103→  const {
   104→    controlState,
   105→    isAgentControlling,
   106→    actionCatalog: orchestratorActionCatalog,
   107→    executeAction,
   108→  } = useAgentControlOrchestrator({
   109→    mode,
   110→    stockContext: baseContextPayload,
   111→  });
   112→
   113→  const actionCatalog = useMemo(
   114→    () => buildActionCatalog({ pathname: location.pathname, mode, stockContext: baseContextPayload }),
   115→    [baseContextPayload, location.pathname, mode],
   116→  );
   117→
   118→  const buildControlContextPayload = useCallback((prompt = '') => {
   119→    const uiSnapshot = buildUiSnapshot({
   120→      pathname: location.pathname,
   121→      mode,
   122→      locationState: location.state || null,
   123→      visibleSections: getVisibleSectionsByMode(mode),
   124→      selectedEntities: {
   125→        stock_code: baseContextPayload?.stock_code || null,
   126→        stock_name: baseContextPayload?.stock_name || null,
   127→        date_key: baseContextPayload?.date || null,
   128→        case_id: baseContextPayload?.case_id || null,
   129→      },
   130→      filters: {
   131→        tab: location.pathname.startsWith('/portfolio') ? 'portfolio' : mode,
   132→      },
   133→      portfolioSummary: baseContextPayload?.portfolio_summary || null,
   134→    });
   135→
   136→    return {
   137→      ...(baseContextPayload || {}),
   138→      ui_snapshot: uiSnapshot,
   139→      action_catalog: actionCatalog,
   140→      interaction_state: {
   141→        source: 'agent_dock',
   142→        mode,
   143→        route: location.pathname,
   144→        last_prompt: prompt || null,
   145→        search_enabled: searchEnabled,
   146→        control_phase: controlState.phase,
   147→        control_active: isAgentControlling,
   148→      },
   149→    };
   150→  }, [actionCatalog, baseContextPayload, controlState.phase, isAgentControlling, location.pathname, location.state, mode, searchEnabled]);
   151→
   152→  const handleSlashCommand = useCallback((command) => {
   153→    setShowSlashMenu(false);
   154→    setSlashQuery('');
   155→
   156→    const action = command.action;
   157→    if (action.type === 'navigate') {
   158→      navigate(action.path, action.tab ? { state: { tab: action.tab } } : undefined);
   159→    } else if (action.type === 'action') {
   160→      const matchedAction = orchestratorActionCatalog.find((item) => item.id === action.actionId);
   161→      if (matchedAction) {
   162→        executeAction(matchedAction, { contextPayload: buildControlContextPayload('') });
   163→      } else {
   164→        setInlineMessage({ text: '현재 화면에서 사용할 수 없는 명령이에요.', canvasPrompt: null });
   165→      }
   166→    } else if (action.type === 'param') {
   167→      if (action.prefix) {
   168→        setActivePrefix({ label: command.desc, prefix: action.prefix });
   169→        setInput('');
   170→      }
   171→      if (action.key === 'use_web_search') {
   172→        setSearchEnabled(true);
   173→      }
   174→    }
   175→  }, [navigate, orchestratorActionCatalog, executeAction, buildControlContextPayload]);
   176→
   177→  const submitPromptToCanvas = useCallback((prompt) => {
   178→    const payload = buildControlContextPayload(prompt);
   179→
   180→    navigate('/agent', {
   181→      state: {
   182→        mode,
   183→        initialPrompt: prompt.trim(),
   184→        contextPayload: payload,
   185→        useWebSearch: searchEnabled,
   186→        resetConversation: location.pathname !== '/agent',
   187→      },
   188→    });
   189→  }, [buildControlContextPayload, location.pathname, mode, navigate, searchEnabled]);
   190→
   191→  const routePrompt = useCallback(async (prompt, payload) => {
   192→    const response = await authFetch(`${API_BASE_URL}/api/v1/tutor/route`, {
   193→      method: 'POST',
   194→      headers: { 'Content-Type': 'application/json' },
   195→      body: JSON.stringify({
   196→        message: prompt,
   197→        mode,
   198→        context_text: JSON.stringify(payload),
   199→        ui_snapshot: payload.ui_snapshot || null,
   200→        action_catalog: payload.action_catalog || [],
   201→        interaction_state: payload.interaction_state || null,
   202→      }),
   203→    });
   204→    if (!response.ok) {
   205→      throw new Error('route_failed');
   206→    }
   207→    return response.json();
   208→  }, [mode]);
   209→
   210→  if (shouldHide) return null;
   211→
   212→  // 모드 자동 결정: 교육 → 대화, 나머지 → 분석
   213→  const effectiveDockMode = dockMode || (mode === 'education' ? 'chat' : 'canvas');
   214→
   215→  const phaseTextByPhase = {
   216→    thinking: '에이전트 분석 중',
   217→    tool_call: '도구 실행 중',
   218→    answering: '답변 생성 중',
   219→    stopped: '중단됨',
   220→    notice: '답변 생성 중',
   221→    error: '오류 발생',
   222→    idle: '대기 중',
   223→  };
   224→  const isActivelyWorking = isStreamingActive || isAgentRoute;
   225→  const dockStatusText = isAgentRoute
   226→    ? (phaseTextByPhase[agentStatus?.phase] || phaseTextByPhase.idle)
   227→    : '질문하세요';
   228→  const shouldShowChevron = hasActiveSession && !isAgentRoute;
   229→  const pulseActive = isRouting || isAgentControlling || isStreamingActive;
   230→  const statusDotClass = pulseActive ? 'agent-status-dot-pulse' : '';
   231→
   232→  const submitPrompt = async (prompt) => {
   233→    const raw = String(prompt || '').trim();
   234→    const normalized = activePrefix ? `${activePrefix.prefix}${raw}` : raw;
   235→    if (!normalized) return;
   236→
   237→    // 대화 모드 → TutorModal 열기
   238→    if (effectiveDockMode === 'chat') {
   239→      openTutor(normalized);
   240→      setInput('');
   241→      setActivePrefix(null);
   242→      return;
   243→    }
   244→
   245→    const controlPayload = buildControlContextPayload(normalized);
   246→    setIsRouting(true);
   247→    setInlineMessage(null);
   248→
   249→    try {
   250→      const decision = await routePrompt(normalized, controlPayload);
   251→      const nextDecision = decision?.decision;
   252→
   253→      if (nextDecision === 'inline_action') {
   254→        const matchedAction = orchestratorActionCatalog.find((item) => item.id === decision?.action_id);
   255→        if (!matchedAction) {
   256→          setInlineMessage({
   257→            text: '실행 가능한 액션을 찾지 못했어요.',
   258→            canvasPrompt: normalized,
   259→          });
   260→        } else {
   261→          await executeAction(matchedAction, {
   262→            contextPayload: controlPayload,
   263→            prompt: normalized,
   264→          });
   265→        }
   266→      } else if (nextDecision === 'open_canvas') {
   267→        submitPromptToCanvas(decision?.canvas_prompt || normalized);
   268→      } else {
   269→        setInlineMessage({
   270→          text: decision?.inline_text || '자세히 보려면 캔버스를 열어주세요.',
   271→          canvasPrompt: decision?.canvas_prompt || normalized,
   272→        });
   273→      }
   274→    } catch {
   275→      setInlineMessage({
   276→        text: '자세한 분석은 캔버스에서 확인할 수 있어요.',
   277→        canvasPrompt: normalized,
   278→      });
   279→    } finally {
   280→      setIsRouting(false);
   281→    }
   282→
   283→    setInput('');
   284→    setActivePrefix(null);
   285→  };
   286→
   287→  const handleSubmit = async (event) => {
   288→    event.preventDefault();
   289→    await submitPrompt(input || suggestedPrompt);
   290→  };
   291→
   292→  const handleResumeChat = () => {
   293→    navigate('/agent', {
   294→      state: {
   295→        mode,
   296→        contextPayload: buildControlContextPayload(''),
   297→        useWebSearch: searchEnabled,
   298→      },
   299→    });
   300→  };
   301→
   302→  return (
   303→    <div
   304→      className="pointer-events-none fixed left-0 right-0 z-30 flex justify-center px-4 pb-2"
   305→      style={{ bottom: `calc(${hideBottomNav ? '0px' : 'var(--bottom-nav-h,68px)'} + var(--keyboard-offset,0px))` }}
   306→    >
   307→      <div className="w-full max-w-mobile space-y-1.5">
   308→        {/* 인라인 메시지 (트레이 대체 — 필요할 때만 노출) */}
   309→        {inlineMessage?.text && (
   310→          <div className="pointer-events-auto flex items-center justify-between gap-2 rounded-[14px] border border-[var(--agent-border,#E8EBED)] bg-white px-3 py-2 shadow-[var(--agent-shadow)]">
   311→            <p className="min-w-0 truncate text-[12px] text-[#6B7684]">{inlineMessage.text}</p>
   312→            {inlineMessage.canvasPrompt && (
   313→              <button
   314→                type="button"
   315→                onClick={() => {
   316→                  submitPromptToCanvas(inlineMessage.canvasPrompt);
   317→                  setInlineMessage(null);
   318→                }}
   319→                className="flex-shrink-0 text-[12px] font-semibold text-[#FF6B00] active:opacity-70"
   320→              >
   321→                자세히
   322→              </button>
   323→            )}
   324→          </div>
   325→        )}
   326→
   327→        {/* 볼드 입력바 */}
   328→        <AgentControlPulse active={pulseActive} mode={effectiveDockMode}>
   329→          <div className="pointer-events-auto relative rounded-[20px] bg-white shadow-[0_2px_16px_rgba(0,0,0,0.08)]">
   330→            {/* 상단 상태 라인 (항상 노출) */}
   331→            <div className="flex items-center gap-2 border-b border-[#F2F4F6] px-3 py-1.5">
   332→              <button
   333→                type="button"
   334→                onClick={hasActiveSession ? handleResumeChat : undefined}
   335→                className={`flex min-w-0 flex-1 items-center gap-2 text-left ${hasActiveSession ? 'active:bg-[#F7F8FA]' : ''}`}
   336→              >
   337→                <span className={`h-1.5 w-1.5 rounded-full ${
   338→                  isActivelyWorking
   339→                    ? (effectiveDockMode === 'canvas' ? 'bg-[#1D6FDE]' : 'bg-[#FF6B00]')
   340→                    : 'bg-[#16A34A]'
   341→                } ${statusDotClass}`} />
   342→                <div className="min-w-0">
   343→                  <p className={`truncate text-[12px] font-medium ${isActivelyWorking ? 'text-[#4E5968]' : 'text-[#166534]'}`}>
   344→                    {dockStatusText}
   345→                  </p>
   346→                </div>
   347→                {shouldShowChevron && (
   348→                  <svg className="ml-auto text-[#B0B8C1]" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
   349→                    <path d="m9 18 6-6-6-6" />
   350→                  </svg>
   351→                )}
   352→              </button>
   353→
   354→              {/* 모드 토글: 대화 / 분석 */}
   355→              <div className="flex items-center gap-0.5">
   356→                <button
   357→                  type="button"
   358→                  onClick={() => setDockMode('chat')}
   359→                  className={`rounded-full px-2 py-1 text-[11px] font-medium transition-colors ${
   360→                    effectiveDockMode === 'chat'
   361→                      ? 'bg-[#FF6B00]/10 text-[#FF6B00]'
   362→                      : 'text-[#8B95A1]'
   363→                  }`}
   364→                >
   365→                  대화
   366→                </button>
   367→                <button
   368→                  type="button"
   369→                  onClick={() => setDockMode('canvas')}
   370→                  className={`rounded-full px-2 py-1 text-[11px] font-medium transition-colors ${
   371→                    effectiveDockMode === 'canvas'
   372→                      ? 'bg-[#1D6FDE]/10 text-[#1D6FDE]'
   373→                      : 'text-[#8B95A1]'
   374→                  }`}
   375→                >
   376→                  에이전트
   377→                </button>
   378→              </div>
   379→
   380→              <div className="ml-auto flex items-center gap-1">
   381→                <button
   382→                  type="button"
   383→                  onClick={() => setSearchEnabled((prev) => !prev)}
   384→                  className={`flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full transition-colors ${
   385→                    searchEnabled
   386→                      ? 'bg-[#FFF2E8] text-[#FF6B00]'
   387→                      : 'bg-[#F2F4F6] text-[#8B95A1]'
   388→                  }`}
   389→                  aria-label={searchEnabled ? '인터넷 검색 켜짐' : '인터넷 검색 꺼짐'}
   390→                  title={searchEnabled ? '인터넷 검색: 켜짐' : '인터넷 검색: 꺼짐'}
   391→                >
   392→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
   393→                    <circle cx="12" cy="12" r="9" />
   394→                    <path d="M3 12h18" />
   395→                    <path d="M12 3a15 15 0 0 1 0 18" />
   396→                    <path d="M12 3a15 15 0 0 0 0 18" />
   397→                  </svg>
   398→                </button>
   399→
   400→                <button
   401→                  type="button"
   402→                  onClick={() => navigate('/agent/history', { state: { mode, contextPayload: buildControlContextPayload('') } })}
   403→                  className="flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full bg-[#F2F4F6] text-[#6B7684] transition-colors active:bg-[#E8EBED]"
   404→                  aria-label="대화 기록 보기"
   405→                  title="대화 기록 보기"
   406→                >
   407→                  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round">
   408→                    <path d="M12 8v5l3 2" />
   409→                    <circle cx="12" cy="12" r="9" />
   410→                  </svg>
   411→                </button>
   412→              </div>
   413→            </div>
   414→
   415→            {showSlashMenu && (
   416→              <SlashCommandMenu
   417→                query={slashQuery}
   418→                onSelect={handleSlashCommand}
   419→                onClose={() => { setShowSlashMenu(false); setSlashQuery(''); }}
   420→                visible={showSlashMenu}
   421→              />
   422→            )}
   423→
   424→            <form
   425→              onSubmit={handleSubmit}
   426→              className="flex h-12 items-center gap-2.5 px-3"
   427→            >
   428→              <button
   429→                type="button"
   430→                onClick={() => submitPrompt(suggestedPrompt)}
   431→                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
   432→                aria-label="추천 질문 사용"
   433→              >
   434→                <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
   435→                  <path d="M12 3l2 5 5 2-5 2-2 5-2-5-5-2 5-2 2-5z" />
   436→                  <path d="M19 4l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
   437→                  <path d="M5.5 15l.7 1.6 1.6.7-1.6.7-.7 1.6-.7-1.6-1.6-.7 1.6-.7.7-1.6z" />
   438→                </svg>
   439→              </button>
   440→
   441→              <div className="flex min-w-0 flex-1 items-center gap-1.5">
   442→                {activePrefix && (
   443→                  <span className="inline-flex shrink-0 items-center gap-1 rounded-full border border-[#FF6B00]/20 bg-[#FFF2E8] px-2.5 py-1 text-[12px] font-semibold text-[#FF6B00]">
   444→                    {activePrefix.label}
   445→                    <button
   446→                      type="button"
   447→                      onClick={() => setActivePrefix(null)}
   448→                      className="ml-0.5 text-[#FF6B00]/60 hover:text-[#FF6B00]"
   449→                      aria-label="명령어 칩 제거"
   450→                    >
   451→                      ✕
   452→                    </button>
   453→                  </span>
   454→                )}
   455→                <input
   456→                  type="text"
   457→                  value={input}
   458→                  onChange={(event) => {
   459→                    const val = event.target.value;
   460→                    setInput(val);
   461→                    if (val.startsWith('/')) {
   462→                      setShowSlashMenu(true);
   463→                      setSlashQuery(val.slice(1));
   464→                    } else {
   465→                      setShowSlashMenu(false);
   466→                      setSlashQuery('');
   467→                    }
   468→                  }}
   469→                  onKeyDown={(e) => {
   470→                    if (showSlashMenu && (e.key === 'ArrowUp' || e.key === 'ArrowDown' || e.key === 'Enter')) {
   471→                      e.preventDefault();
   472→                    }
   473→                    if (e.key === 'Escape' && showSlashMenu) {
   474→                      setShowSlashMenu(false);
   475→                      setSlashQuery('');
   476→                    }
   477→                    if (e.key === 'Backspace' && !input && activePrefix) {
   478→                      setActivePrefix(null);
   479→                    }
   480→                  }}
   481→                  placeholder={activePrefix ? '내용을 입력하세요' : (input ? placeholder : (effectiveDockMode === 'chat' ? '궁금한 것을 물어보세요' : suggestedPrompt))}
   482→                  data-agent-dock-input
   483→                  className="min-w-0 flex-1 bg-transparent text-[14px] text-[#191F28] placeholder:text-[#B0B8C1] focus:outline-none"
   484→                  aria-label="에이전트 질문 입력"
   485→                />
   486→              </div>
   487→
   488→              <button
   489→                type="submit"
   490→                className="flex h-7 w-7 flex-shrink-0 items-center justify-center rounded-full bg-[#FF6B00] text-white shadow-sm active:scale-95"
   491→                aria-label="질문 전송"
   492→                disabled={isRouting}
   493→              >
   494→                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
   495→                  <path d="m12 19V5" />
   496→                  <path d="m5 12 7-7 7 7" />
   497→                </svg>
   498→              </button>
   499→            </form>
   500→          </div>
   501→        </AgentControlPulse>
   502→      </div>
   503→    </div>
   504→  );
   505→}
