    12→function splitParagraphs(text) {
    13→  if (!text) return [];
    14→  return text
    15→    .split(/\n{2,}/)
    16→    .map((item) => item.trim())
    17→    .filter(Boolean);
    18→}
    19→
    20→function splitSentences(text) {
    21→  if (!text) return [];
    22→  return text
    23→    .replace(/\s+/g, ' ')
    24→    .split(/(?<=[.!?])\s+/)
    25→    .map((item) => item.trim())
    26→    .filter(Boolean);
    27→}
    28→
    29→function extractBullets(text, fallbackSentences) {
    30→  const fromLines = String(text || '')
    31→    .split('\n')
    32→    .map((line) => line.trim())
    33→    .filter((line) => /^([\-•*]|\d+\.)\s+/.test(line))
    34→    .map((line) => line.replace(/^([\-•*]|\d+\.)\s+/, '').trim())
    35→    .filter(Boolean);
    36→
    37→  if (fromLines.length > 0) {
    38→    return fromLines.slice(0, 3);
    39→  }
    40→
    41→  return fallbackSentences.slice(2, 5).map((line) => line.replace(/\s+/g, ' ').trim()).filter(Boolean);
    42→}
    43→
    44→function hasStructuredSignal(text) {
    45→  if (!text) return false;
    46→
    47→  const bulletPattern = /(^|\n)\s*([\-•*]|\d+\.)\s+\S+/m;
    48→  const headingPattern = /(^|\n)\s*(핵심|요약|정리|포인트|근거|리스크|액션)\s*[:：]/m;
    49→  const markdownHeadingPattern = /(^|\n)\s*#{2,4}\s+\S+/m;
    50→
    51→  return bulletPattern.test(text) || headingPattern.test(text) || markdownHeadingPattern.test(text);
    52→}
    53→
    54→function buildTitle(mode, contextPayload, userPrompt) {
    55→  if (mode === 'stock' && contextPayload?.stock_name) {
    56→    return `${contextPayload.stock_name} 캔버스`;
    57→  }
    58→
    59→  if (userPrompt && userPrompt.length <= 28) {
    60→    return userPrompt;
    61→  }
    62→
    63→  if (mode === 'education') return '학습 캔버스';
    64→  if (mode === 'home') return '오늘 시장 흐름';
    65→
    66→  return '에이전트 캔버스';
    67→}
    68→
    69→function buildActions(mode) {
    70→  if (mode === 'stock') {
    71→    return ['내 포트폴리오 영향은?', '리스크 포인트만 추려줘'];
    72→  }
    73→
    74→  if (mode === 'education') {
    75→    return ['핵심 개념만 복습하기', '이걸 쉽게 다시 설명해줘'];
    76→  }
    77→
    78→  return ['핵심만 다시 정리해줘', '이 내용 더 쉽게 설명해줘'];
