    61→
    62→  // 전역 키보드 이벤트 등록
    63→  useEffect(() => {
    64→    if (!visible) return undefined;
    65→    window.addEventListener('keydown', handleKeyDown);
    66→    return () => window.removeEventListener('keydown', handleKeyDown);
    67→  }, [visible, handleKeyDown]);
    68→
    69→  // 활성 아이템 스크롤 보장
    70→  useEffect(() => {
    71→    if (!menuRef.current) return;
    72→    const activeEl = menuRef.current.querySelector('[data-active="true"]');
    73→    if (activeEl) {
    74→      activeEl.scrollIntoView({ block: 'nearest' });
    75→    }
    76→  }, [activeIndex]);
    77→
    78→  if (!visible || filtered.length === 0) return null;
    79→
    80→  return (
    81→    <div
    82→      ref={menuRef}
    83→      className="absolute bottom-full left-0 right-0 z-50 mb-2 overflow-hidden rounded-xl bg-white shadow-lg ring-1 ring-black/5"
    84→      role="listbox"
    85→      aria-label="슬래시 커맨드 목록"
    86→    >
    87→      <div className="max-h-[240px] overflow-y-auto py-1">
    88→        {filtered.slice(0, 5).map((command, index) => {
    89→          const isActive = index === activeIndex;
    90→          return (
    91→            <button
    92→              key={command.cmd}
    93→              type="button"
    94→              role="option"
    95→              aria-selected={isActive}
    96→              data-active={isActive}
    97→              onClick={() => onSelect(command)}
    98→              onMouseEnter={() => setActiveIndex(index)}
    99→              className={`flex w-full items-center gap-3 px-4 py-2.5 text-left transition-colors ${
   100→                isActive ? 'bg-[#FFF2E8]' : 'hover:bg-[#F7F8FA]'
   101→              }`}
   102→            >
