     1→import { useCallback, useEffect, useRef, useState } from 'react';
     2→
     3→const SLASH_COMMANDS = [
     4→  { cmd: '/chart', aliases: ['/시각화'], desc: '차트 생성', icon: '📊', action: { type: 'param', key: 'use_visualization', value: true, prefix: '[시각화 요청] ' } },
     5→  { cmd: '/search', aliases: ['/검색'], desc: '웹 검색', icon: '🔍', action: { type: 'param', key: 'use_web_search', value: true } },
     6→  { cmd: '/compare', aliases: ['/비교'], desc: '종목 비교', icon: '⚖️', action: { type: 'param', key: 'response_mode', value: 'comparison', prefix: '[비교 분석] ' } },
     7→  { cmd: '/quiz', aliases: ['/퀴즈'], desc: '퀴즈 시작', icon: '❓', action: { type: 'navigate', path: '/education', tab: 'quiz' } },
     8→  { cmd: '/portfolio', aliases: ['/포트폴리오'], desc: '내 자산', icon: '💼', action: { type: 'action', actionId: 'nav_portfolio' } },
     9→  { cmd: '/buy', aliases: ['/매수'], desc: '매수', icon: '📈', action: { type: 'action', actionId: 'buy_stock' } },
    10→  { cmd: '/sell', aliases: ['/매도'], desc: '매도', icon: '📉', action: { type: 'action', actionId: 'sell_stock' } },
    11→  { cmd: '/history', aliases: ['/기록'], desc: '대화 기록', icon: '🕐', action: { type: 'navigate', path: '/agent/history' } },
    12→];
    13→
    14→export { SLASH_COMMANDS };
    15→
    16→/**
    17→ * SlashCommandMenu - "/" 입력 시 나타나는 슬래시 커맨드 팝업 메뉴
    18→ *
    19→ * @param {string} query - "/" 뒤에 입력된 텍스트 (예: 사용자가 "/ch" 입력 → query = "ch")
    20→ * @param {function} onSelect - 커맨드 선택 시 호출 (command 객체 전달)
    21→ * @param {function} onClose - 메뉴 닫기 시 호출
    22→ * @param {boolean} visible - 메뉴 표시 여부
    23→ */
    24→export default function SlashCommandMenu({ query, onSelect, onClose, visible }) {
    25→  const [activeIndex, setActiveIndex] = useState(0);
    26→  const menuRef = useRef(null);
    27→
    28→  // query로 커맨드 필터링 (cmd, aliases 모두 매칭)
    29→  const filtered = SLASH_COMMANDS.filter((command) => {
    30→    const q = (query || '').toLowerCase();
    31→    if (!q) return true;
    32→    const cmdMatch = command.cmd.slice(1).toLowerCase().startsWith(q);
    33→    const aliasMatch = command.aliases.some((alias) => alias.slice(1).toLowerCase().startsWith(q));
    34→    const descMatch = command.desc.toLowerCase().includes(q);
    35→    return cmdMatch || aliasMatch || descMatch;
    36→  });
    37→
    38→  // query 변경 시 activeIndex 리셋
    39→  useEffect(() => {
    40→    setActiveIndex(0);
    41→  }, [query]);
    42→
    43→  // 키보드 네비게이션 핸들러
    44→  const handleKeyDown = useCallback((e) => {
    45→    if (!visible || filtered.length === 0) return;
    46→
    47→    if (e.key === 'ArrowDown') {
    48→      e.preventDefault();
    49→      setActiveIndex((prev) => (prev + 1) % filtered.length);
    50→    } else if (e.key === 'ArrowUp') {
    51→      e.preventDefault();
    52→      setActiveIndex((prev) => (prev - 1 + filtered.length) % filtered.length);
    53→    } else if (e.key === 'Enter') {
    54→      e.preventDefault();
    55→      onSelect(filtered[activeIndex]);
    56→    } else if (e.key === 'Escape') {
    57→      e.preventDefault();
    58→      onClose();
    59→    }
    60→  }, [visible, filtered, activeIndex, onSelect, onClose]);
    61→
    62→  // 전역 키보드 이벤트 등록
    63→  useEffect(() => {
    64→    if (!visible) return undefined;
    65→    window.addEventListener('keydown', handleKeyDown);
    66→    return () => window.removeEventListener('keydown', handleKeyDown);
    67→  }, [visible, handleKeyDown]);
    68→
    69→  // 활성 아이템 스크롤 보장
    70→  useEffect(() => {
    71→    if (!menuRef.current) return;
    72→    const activeEl = menuRef.current.querySelector('[data-active="true"]');
    73→    if (activeEl) {
    74→      activeEl.scrollIntoView({ block: 'nearest' });
    75→    }
    76→  }, [activeIndex]);
    77→
    78→  if (!visible || filtered.length === 0) return null;
    79→
    80→  return (
    81→    <div
    82→      ref={menuRef}
    83→      className="absolute bottom-full left-0 right-0 z-50 mb-2 overflow-hidden rounded-xl bg-white shadow-lg ring-1 ring-black/5"
    84→      role="listbox"
    85→      aria-label="슬래시 커맨드 목록"
    86→    >
    87→      <div className="max-h-[240px] overflow-y-auto py-1">
    88→        {filtered.slice(0, 5).map((command, index) => {
    89→          const isActive = index === activeIndex;
    90→          return (
    91→            <button
    92→              key={command.cmd}
    93→              type="button"
    94→              role="option"
    95→              aria-selected={isActive}
    96→              data-active={isActive}
    97→              onClick={() => onSelect(command)}
    98→              onMouseEnter={() => setActiveIndex(index)}
    99→              className={`flex w-full items-center gap-3 px-4 py-2.5 text-left transition-colors ${
   100→                isActive ? 'bg-[#FFF2E8]' : 'hover:bg-[#F7F8FA]'
   101→              }`}
   102→            >
   103→              <span className="flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-lg bg-[#F7F8FA] text-[16px]">
   104→                {command.icon}
   105→              </span>
   106→              <div className="min-w-0 flex-1">
   107→                <div className="flex items-center gap-2">
   108→                  <span className="text-[14px] font-semibold text-[#191F28]">{command.cmd}</span>
   109→                  {command.aliases.map((alias) => (
   110→                    <span key={alias} className="text-[12px] text-[#8B95A1]">{alias}</span>
   111→                  ))}
   112→                </div>
   113→                <p className="text-[12px] text-[#6B7684]">{command.desc}</p>
   114→              </div>
   115→              {isActive && (
   116→                <span className="flex-shrink-0 text-[11px] text-[#B0B8C1]">Enter</span>
   117→              )}
   118→            </button>
   119→          );
   120→        })}
   121→      </div>
   122→    </div>
   123→  );
   124→}
