     1→function pickAssistantText(messages) {
     2→  if (!Array.isArray(messages)) return '';
     3→  for (let idx = messages.length - 1; idx >= 0; idx -= 1) {
     4→    const message = messages[idx];
     5→    if (message?.role === 'assistant' && typeof message.content === 'string' && message.content.trim()) {
     6→      return message.content.trim();
     7→    }
     8→  }
     9→  return '';
    10→}
    11→
    12→function splitParagraphs(text) {
    13→  if (!text) return [];
    14→  return text
    15→    .split(/\n{2,}/)
    16→    .map((item) => item.trim())
    17→    .filter(Boolean);
    18→}
    19→
    20→function splitSentences(text) {
    21→  if (!text) return [];
    22→  return text
    23→    .replace(/\s+/g, ' ')
    24→    .split(/(?<=[.!?])\s+/)
    25→    .map((item) => item.trim())
    26→    .filter(Boolean);
    27→}
    28→
    29→function extractBullets(text, fallbackSentences) {
    30→  const fromLines = String(text || '')
    31→    .split('\n')
    32→    .map((line) => line.trim())
    33→    .filter((line) => /^([\-•*]|\d+\.)\s+/.test(line))
    34→    .map((line) => line.replace(/^([\-•*]|\d+\.)\s+/, '').trim())
    35→    .filter(Boolean);
    36→
    37→  if (fromLines.length > 0) {
    38→    return fromLines.slice(0, 3);
    39→  }
    40→
    41→  return fallbackSentences.slice(2, 5).map((line) => line.replace(/\s+/g, ' ').trim()).filter(Boolean);
    42→}
    43→
    44→function hasStructuredSignal(text) {
    45→  if (!text) return false;
    46→
    47→  const bulletPattern = /(^|\n)\s*([\-•*]|\d+\.)\s+\S+/m;
    48→  const headingPattern = /(^|\n)\s*(핵심|요약|정리|포인트|근거|리스크|액션)\s*[:：]/m;
    49→  const markdownHeadingPattern = /(^|\n)\s*#{2,4}\s+\S+/m;
    50→
    51→  return bulletPattern.test(text) || headingPattern.test(text) || markdownHeadingPattern.test(text);
    52→}
    53→
    54→function buildTitle(mode, contextPayload, userPrompt) {
    55→  if (mode === 'stock' && contextPayload?.stock_name) {
    56→    return `${contextPayload.stock_name} 캔버스`;
    57→  }
    58→
    59→  if (userPrompt && userPrompt.length <= 28) {
    60→    return userPrompt;
    61→  }
    62→
    63→  if (mode === 'education') return '학습 캔버스';
    64→  if (mode === 'home') return '오늘 시장 흐름';
    65→
    66→  return '에이전트 캔버스';
    67→}
    68→
    69→function buildActions(mode) {
    70→  if (mode === 'stock') {
    71→    return ['내 포트폴리오 영향은?', '리스크 포인트만 추려줘'];
    72→  }
    73→
    74→  if (mode === 'education') {
    75→    return ['핵심 개념만 복습하기', '이걸 쉽게 다시 설명해줘'];
    76→  }
    77→
    78→  return ['핵심만 다시 정리해줘', '이 내용 더 쉽게 설명해줘'];
    79→}
    80→
    81→function normalizeUiActions(uiActions) {
    82→  if (!Array.isArray(uiActions)) return [];
    83→
    84→  return uiActions
    85→    .map((action, index) => {
    86→      if (!action) return null;
    87→      if (typeof action === 'string') {
    88→        return {
    89→          id: `action-${index}`,
    90→          label: action,
    91→          type: 'prompt',
    92→          prompt: action,
    93→        };
    94→      }
    95→
    96→      const label = action.label || action.title || action.text || action.prompt;
    97→      if (!label) return null;
    98→
    99→      return {
   100→        id: action.id || `action-${index}`,
   101→        label,
   102→        type: action.type || 'prompt',
   103→        prompt: action.prompt || label,
   104→        params: action.params || {},
   105→      };
   106→    })
   107→    .filter(Boolean);
   108→}
   109→
   110→function buildModeLabel(mode) {
   111→  if (mode === 'stock') return '종목 컨텍스트';
   112→  if (mode === 'education') return '학습 컨텍스트';
   113→  if (mode === 'my') return 'MY 컨텍스트';
   114→  return '홈 컨텍스트';
   115→}
   116→
   117→function normalizeSources(sources) {
   118→  if (!Array.isArray(sources)) return [];
   119→
   120→  return sources
   121→    .filter((item) => item && typeof item === 'object')
   122→    .map((item) => ({
   123→      title: String(item.title || item.content || '출처').trim(),
   124→      url: String(item.url || '').trim(),
   125→      source_kind: String(item.source_kind || item.type || 'internal').trim(),
   126→      is_reachable: item.is_reachable === null || item.is_reachable === undefined
   127→        ? null
   128→        : Boolean(item.is_reachable),
   129→      metrics: item.metrics && typeof item.metrics === 'object' ? item.metrics : null,
   130→    }));
   131→}
   132→
   133→function collectMetricRows(sources) {
   134→  const labelMap = {
   135→    revenue: '매출액',
   136→    operating_income: '영업이익',
   137→    net_income: '당기순이익',
   138→    total_assets: '자산총계',
   139→    total_liabilities: '부채총계',
   140→  };
   141→
   142→  for (const source of sources) {
   143→    if (!source?.metrics) continue;
   144→    const rows = Object.entries(source.metrics)
   145→      .filter(([key, value]) => labelMap[key] && Number.isFinite(Number(value)))
   146→      .map(([key, value]) => ({
   147→        key,
   148→        label: labelMap[key],
   149→        value: Number(value),
   150→      }));
   151→
   152→    if (rows.length > 0) {
   153→      return rows;
   154→    }
   155→  }
   156→
   157→  return [];
   158→}
   159→
   160→export default function composeCanvasState({
   161→  messages,
   162→  mode = 'home',
   163→  contextPayload = null,
   164→  aiStatus = null,
   165→  userPrompt = '',
   166→  assistantText: assistantTextOverride = '',
   167→  assistantTurn = null,
   168→}) {
   169→  const assistantText = (assistantTextOverride || pickAssistantText(messages) || '').trim();
   170→  const structured = assistantTurn?.structured && typeof assistantTurn.structured === 'object'
   171→    ? assistantTurn.structured
   172→    : null;
   173→  const paragraphs = splitParagraphs(assistantText);
   174→  const sentences = splitSentences(assistantText);
   175→  const hasStructuredMarkdown = hasStructuredSignal(assistantText);
   176→  const normalizedUiActions = normalizeUiActions(assistantTurn?.uiActions);
   177→  const normalizedSources = normalizeSources(assistantTurn?.sources);
   178→  const metricRows = collectMetricRows(normalizedSources);
   179→  const fallbackActions = buildActions(mode).map((action, index) => ({
   180→    id: `fallback-${index}`,
   181→    label: action,
   182→    prompt: action,
   183→  }));
   184→
   185→  const structuredActions = Array.isArray(structured?.suggested_actions)
   186→    ? structured.suggested_actions
   187→      .map((item, index) => ({
   188→        id: `structured-action-${index}`,
   189→        label: String(item || '').trim(),
   190→        prompt: String(item || '').trim(),
   191→      }))
   192→      .filter((item) => item.label)
   193→    : [];
   194→
   195→  const keyPoint = structured?.summary || sentences[0] || paragraphs[0] || '';
   196→  const explanation = sentences.slice(1, 3).join(' ') || paragraphs[1] || '';
   197→  const bullets = hasStructuredMarkdown ? extractBullets(assistantText, sentences) : [];
   198→  const quote = hasStructuredMarkdown ? (sentences[sentences.length - 1] || '') : '';
   199→
   200→  return {
   201→    title: buildTitle(mode, contextPayload, userPrompt),
   202→    modeLabel: buildModeLabel(mode),
   203→    viewType: assistantText ? (structured || hasStructuredMarkdown ? 'structured' : 'plain') : 'empty',
   204→    keyPoint,
   205→    explanation,
   206→    bullets,
   207→    quote,
   208→    textBlocks: paragraphs.length > 0 ? paragraphs : (assistantText ? [assistantText] : []),
   209→    actions: normalizedUiActions.length > 0
   210→      ? normalizedUiActions
   211→      : (structuredActions.length > 0 ? structuredActions : fallbackActions),
   212→    aiStatus: aiStatus || '대기 중',
   213→    userPrompt,
   214→    structured,
   215→    rawAssistantText: assistantText,
   216→    sources: normalizedSources,
   217→    metricRows,
   218→  };
   219→}
